// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}
	//Type appropriate comment here, and begin script below
	var OUPermissions  = new GlideAjax('ClientOrganizationalScripts');
	OUPermissions.addParam('sysparm_name','checkOffice_name');
	OUPermissions.addParam("office_name", g_form.getValue('office_name'));

	OUPermissions.addParam("sys_id", g_form.getUniqueValue());

	OUPermissions.getXML(f_returnIsDuplicate);

	function f_returnIsDuplicate(response){
		var answer = response.responseXML.documentElement.getAttribute("answer");


		if(answer == 'true')
			g_form.showErrorBox('office_name',"The OU Name already exists.  In order to create a new OU, the OU Name must be unique.");



	}
}
